   164→                    throw new IllegalSaslStateException("Unexpected challenge in Sasl server state " + state);
   165→            }
   166→        } catch (SaslException | AuthenticationException e) {
   167→            clearCredentials();
   168→            setState(State.FAILED);
   169→            throw e;
   170→        }
