    91→public class SaslServerAuthenticator implements Authenticator {
    92→    private static final Logger LOG = LoggerFactory.getLogger(SaslServerAuthenticator.class);
    93→
    94→    /**
    95→     * The internal state transitions for initial authentication of a channel on the
    96→     * server side are declared in order, starting with {@link #INITIAL_REQUEST} and
    97→     * ending in either {@link #COMPLETE} or {@link #FAILED}.
    98→     * <p>
    99→     * Re-authentication of a channel on the server side starts with the state
   100→     * {@link #REAUTH_PROCESS_HANDSHAKE}. It may then flow to
   101→     * {@link #REAUTH_BAD_MECHANISM} before a transition to {@link #FAILED} if
   102→     * re-authentication is attempted with a mechanism different than the original
   103→     * one; otherwise it joins the authentication flow at the {@link #AUTHENTICATE}
   104→     * state and likewise ends at either {@link #COMPLETE} or {@link #FAILED}.
   105→     */
   106→    private enum SaslState {
   107→        INITIAL_REQUEST,               // May be GSSAPI token, SaslHandshake or ApiVersions for authentication
   108→        HANDSHAKE_OR_VERSIONS_REQUEST, // May be SaslHandshake or ApiVersions
   109→        HANDSHAKE_REQUEST,             // After an ApiVersions request, next request must be SaslHandshake
   110→        AUTHENTICATE,                  // Authentication tokens (SaslHandshake v1 and above indicate SaslAuthenticate headers)
   111→        COMPLETE,                      // Authentication completed successfully
   112→        FAILED,                        // Authentication failed
   113→        REAUTH_PROCESS_HANDSHAKE,      // Initial state for re-authentication, processes SASL handshake request
   114→        REAUTH_BAD_MECHANISM,          // When re-authentication requested with wrong mechanism, generate exception
   115→    }
