   581→    // Visible to override for testing
   582→    protected void enableKafkaSaslAuthenticateHeaders(boolean flag) {
   583→        this.enableKafkaSaslAuthenticateHeaders = flag;
   584→    }
   585→
   586→    private void handleApiVersionsRequest(RequestContext context, ApiVersionsRequest apiVersionsRequest) throws IOException {
   587→        if (saslState != SaslState.HANDSHAKE_OR_VERSIONS_REQUEST)
   588→            throw new IllegalStateException("Unexpected ApiVersions request received during SASL authentication state " + saslState);
   589→
   590→        if (apiVersionsRequest.hasUnsupportedRequestVersion())
   591→            sendKafkaResponse(context, apiVersionsRequest.getErrorResponse(0, Errors.UNSUPPORTED_VERSION.exception()));
   592→        else if (!apiVersionsRequest.isValid())
   593→            sendKafkaResponse(context, apiVersionsRequest.getErrorResponse(0, Errors.INVALID_REQUEST.exception()));
   594→        else {
   595→            metadataRegistry.registerClientInformation(new ClientInformation(apiVersionsRequest.data().clientSoftwareName(),
   596→                apiVersionsRequest.data().clientSoftwareVersion()));
   597→            sendKafkaResponse(context, apiVersionSupplier.get());
   598→            setSaslState(SaslState.HANDSHAKE_REQUEST);
   599→        }
   600→    }
